features.snippet:
genvar i;
always_ff @(posedge clk) begin o_q[0] <= !o_q[0]; end
generate for (i=1; i<W_CNT; i++) begin : gen
/* verilator lint_off MULTIDRIVEN */
    always_ff @(negedge o_q[i-1]) begin o_q[i] <= !o_q[i]; end
/* verilator lint_on MULTIDRIVEN */
end endgenerate

output logic [W_CNT-1:0] o_q;
always_ff @(posedge clk or negedge rst) begin if (!rst) o_q[0] <= 1'b1; else o_q[0] <= !o_q[0]; end
always_ff @(negedge o_q[i-1] or negedge rst) begin if (!rst) o_q[i] <= 1'b0; else o_q[i] <= !o_q[i]; end
